package de.chrgroth.gradle.plugins.releasenotesimport org.gradle.api.Projectimport java.io.Fileopen class ReleasenotesExtension(val project: Project) {    internal val configurations: List<ReleasenotesConfiguration>        get() = additionalConfigurations.plus(defaultConfiguration)    var mainBranch = "main"    var defaultConfiguration = ReleasenotesConfiguration(        outputPath = "src/docs/asciidoc/en/releasenotes_EN.adoc",        snippetsPath = "src/docs/asciidoc/en/next",        templatesPath = "src/docs/asciidoc/en/templates",        bugfixesHeader = "## Bugfixes",        bugfixesFooter = "",        featuresHeader = "## New Features",        featuresFooter = "",        highlightsHeader = "## Highlights",        highlightsFooter = "",        updateNoticesHeader = "## Update Notices",        updateNoticesFooter = "",        dateFormat = "yyyy.MM.dd",    )    var additionalConfigurations: List<ReleasenotesConfiguration> = listOf(        ReleasenotesConfiguration(            outputPath = "src/docs/asciidoc/de/releasenotes_DE.adoc",            snippetsPath = "src/docs/asciidoc/de/next",            templatesPath = "src/docs/asciidoc/de/templates",            bugfixesHeader = "## Behobene Fehler",            bugfixesFooter = "",            featuresHeader = "## Neue Features",            featuresFooter = "",            highlightsHeader = "## Highlights",            highlightsFooter = "",            updateNoticesHeader = "## Aktualisierungshinweise",            updateNoticesFooter = "",            dateFormat = "dd.MM.yyyy",        ),    )}data class ReleasenotesConfiguration(    val outputPath: String,    val snippetsPath: String,    val templatesPath: String,    val bugfixesHeader: String,    val bugfixesFooter: String,    val featuresHeader: String,    val featuresFooter: String,    val highlightsHeader: String,    val highlightsFooter: String,    val updateNoticesHeader: String,    val updateNoticesFooter: String,    val dateFormat: String,) {    fun init(dir: File): ReleaseNotesProcessor = ReleaseNotesProcessor(        outputFile = dir.resolve(outputPath),        snippetsFolder = dir.resolve(snippetsPath),        templatesFolder = dir.resolve(templatesPath),        bugfixesHeader = bugfixesHeader,        bugfixesFooter = bugfixesFooter,        featuresHeader = featuresHeader,        featuresFooter = featuresFooter,        highlightsHeader = highlightsHeader,        highlightsFooter = highlightsFooter,        updateNoticesHeader = updateNoticesHeader,        updateNoticesFooter = updateNoticesFooter,        dateFormat = dateFormat,    )}